// Текст уже извлечён в браузере через JSZip (.docx → word/document.xml → text)
const body = $input.first().json.body || {};
let text = (body.text || '').trim();

if (!text) {
  return [{ json: { has_text: false, error: 'Пустой текст в запросе.' } }];
}

if (text.length < 20) {
  return [{ json: { has_text: false, error: 'Слишком короткий текст из браузера (' + text.length + ' символов).' } }];
}

if (text.length > 15000) text = text.substring(0, 15000);

return [{ json: { has_text: true, text: text, text_length: text.length, source: 'browser-jszip' } }];

// Валидация: убеждаемся что файл (binary) загружен
const item = $input.first();
const binary = item.binary;

if (!binary || Object.keys(binary).length === 0) {
  return [{ json: { valid: false, error: 'Файл не загружен. Прикрепите .docx или .pdf документ.' } }];
}

const key = Object.keys(binary)[0];
const info = binary[key];
const fileName = info.fileName || 'unknown';
const mimeType = (info.mimeType || '').toLowerCase();
const fileSize = info.fileSize || 0;

if (fileSize > 50 * 1024 * 1024) {
  return [{ json: { valid: false, error: 'Файл слишком большой (максимум 50 МБ).' } }];
}

const ext = (fileName.split('.').pop() || '').toLowerCase();
const allowed = ['docx', 'pdf'];
if (!allowed.includes(ext)) {
  return [{ json: { valid: false, error: 'Поддерживаются только .docx и .pdf файлы. Получен: .' + ext } }];
}

return [{ json: { valid: true, binaryKey: key, fileName, mimeType, fileSize }, binary: binary }];

const raw = $input.first().json;

if (raw.error) {
  return [{ json: { has_text: false, error: 'OCR-сервис недоступен: ' + JSON.stringify(raw.error) } }];
}

let text = '';
if (typeof raw === 'string') text = raw;
else if (raw.text) text = raw.text;
else if (raw.result && raw.result.text) text = raw.result.text;
else if (raw.data && raw.data.text) text = raw.data.text;
else if (raw.content) text = raw.content;
else if (raw.output) text = typeof raw.output === 'string' ? raw.output : JSON.stringify(raw.output);

text = (text || '').trim();

if (text.length < 20) {
  return [{ json: { has_text: false, error: 'OCR не смог распознать текст в документе (получено ' + text.length + ' символов).' } }];
}

if (text.length > 15000) text = text.substring(0, 15000);

return [{ json: { has_text: true, text: text, text_length: text.length } }];

// Парсим 4 поля из ответа LLM. Затем валидируем форматы.
try {
  const raw = $input.first().json;
  if (raw.error) {
    return [{ json: { parsed_ok: false, error: 'GigaChat-LLM недоступен.' } }];
  }

  const text = (raw && raw.output && raw.output[0] && raw.output[0].content && raw.output[0].content[0] && raw.output[0].content[0].text) || '';

  // LLM мог вернуть валидный ответ, но пустой output (rate-limit, фильтр и т.п.)
  if (!text) {
    return [{ json: { parsed_ok: false, error: 'GigaChat-LLM вернул пустой ответ. Повторите запрос.' } }];
  }

  const reFio    = /ФИО\s*[:\-]\s*(.+?)(?:\n|$)/i;
  const reBirth  = /Дата\s+рождения\s*[:\-]\s*(.+?)(?:\n|$)/i;
  const rePersonal = /(?:Личный\s+номер|Персональный\s+номер|Номер\s+сотрудника)\s*[:\-]\s*(.+?)(?:\n|$)/i;
  const reSnils  = /(?:СНИЛС|Страховой\s+номер)\s*[:\-]\s*(.+?)(?:\n|$)/i;

  const fioM    = text.match(reFio);
  const birthM  = text.match(reBirth);
  const persM   = text.match(rePersonal);
  const snilsM  = text.match(reSnils);

  let fio = fioM ? fioM[1].trim() : '';
  let birth_date = birthM ? birthM[1].trim() : '';
  let personal_number = persM ? persM[1].trim() : '';
  let snils = snilsM ? snilsM[1].trim() : '';

  // Чистка ФИО: убираем кавычки и финальные знаки препинания
  fio = fio.replace(/^[\"«»''\u201C\u201D\u00AB\u00BB]+|[\"«»''\u201C\u201D\u00AB\u00BB]+$/g, '').trim();
  fio = fio.replace(/[.,;:]+$/g, '').trim();
  fio = fio.normalize('NFC');

  // Унифицируем «не указано/не указан» как пустые значения
  function isAbsent(v) {
    if (!v) return true;
    const lo = v.toLowerCase();
    return lo.includes('не указан') || lo.includes('не указано') || lo.includes('не найден') || lo === '-' || lo === '—' || lo === 'нет';
  }

  if (isAbsent(fio))             fio = '';
  if (isAbsent(birth_date))      birth_date = '';
  if (isAbsent(personal_number)) personal_number = '';
  if (isAbsent(snils))           snils = '';

  // Валидация формата Личного номера ХХХ-ХХХ (6 цифр, дефис)
  // Приводим: убираем пробелы, если есть только 6 цифр — добавим дефис
  if (personal_number) {
    const digits = personal_number.replace(/\D/g, '');
    if (digits.length === 6) {
      personal_number = digits.slice(0, 3) + '-' + digits.slice(3);
    } else if (!/^\d{3}-\d{3}$/.test(personal_number)) {
      // Неверный формат — считаем что номер не указан
      personal_number = '';
    }
  }

  // Валидация формата СНИЛС ХХХ-ХХХ-ХХХ ХХ (11 цифр)
  if (snils) {
    const digits = snils.replace(/\D/g, '');
    if (digits.length === 11) {
      snils = digits.slice(0, 3) + '-' + digits.slice(3, 6) + '-' + digits.slice(6, 9) + ' ' + digits.slice(9, 11);
    } else if (!/^\d{3}-\d{3}-\d{3}\s\d{2}$/.test(snils)) {
      snils = '';
    }
  }

  // SQL-safe ФИО — экранируем LIKE-метасимволы
  const fioForSql = fio.replace(/\\/g, '\\\\').replace(/%/g, '\\%').replace(/_/g, '\\_');

  return [{ json: {
    parsed_ok: true,
    fio: fio,
    fio_for_sql: fioForSql,
    birth_date: birth_date,
    personal_number: personal_number,
    snils: snils
  }}];
} catch (e) {
  return [{ json: { parsed_ok: false, error: 'Ошибка парсинга ответа LLM: ' + e.message } }];
}

// ФАЗА 1: Идентификация служебной записки.
// Проверяем обязательные поля по порядку.
const d = $json;

let step1 = { step: 1, name: 'Идентификация служебной записки' };

if (!d.fio) {
  step1.status = 'not_found';
  step1.message = 'ФИО заявителя отсутствует, нужно предоставить данные';
  return [{ json: { phase1_ok: false, step1: step1, ...d } }];
}

if (!d.birth_date) {
  step1.status = 'not_found';
  step1.message = 'Дата рождения заявителя отсутствует, нужно предоставить данные';
  return [{ json: { phase1_ok: false, step1: step1, ...d } }];
}

// Достаточно одного из двух: Личный номер ИЛИ СНИЛС
if (!d.personal_number && !d.snils) {
  step1.status = 'not_found';
  step1.message = 'Личный номер или СНИЛС заявителя отсутствует, нужно предоставить данные';
  return [{ json: { phase1_ok: false, step1: step1, ...d } }];
}

step1.status = 'ok';
step1.message = 'Служебная записка идентифицирована';
return [{ json: { phase1_ok: true, step1: step1, ...d } }];

// ФАЗА 2: Идентификация заявителя в реестре.
// Возможные исходы:
//   db_error        — Postgres недоступен (onError=continueRegularOutput)
//   not_found       — ФИО нет в employees
//   no_tab_number   — ФИО есть, employee_number = NULL
//   ok              — ФИО + ТН есть → переходим к фазе 3
const items = $input.all();
const rows = items.map(item => item.json).filter(r => r && r.full_name);
const d = $('Фаза 1: проверка полей').first().json;

let step2 = { step: 2, name: 'Идентификация заявителя' };
let phase2_ok = false;
let employee_number = null;

// Postgres-нода с onError=continueRegularOutput при отказе БД отдаёт item с .error без .full_name
const dbError = items.length > 0 && items[0].json && items[0].json.error;
if (dbError) {
  step2.status = 'not_found';
  step2.message = 'Ошибка БД: сервис временно недоступен. Повторите запрос позже.';
  return [{ json: { phase2_ok: false, step2, employee_number, fio: d.fio, fio_for_sql: d.fio_for_sql, birth_date: d.birth_date, personal_number: d.personal_number, snils: d.snils, step1: d.step1 } }];
}

if (rows.length === 0) {
  step2.status = 'not_found';
  step2.message = 'Заявитель не идентифицирован, нужно предоставить дополнительные данные';
} else {
  // Берём первую найденную строку (UNIQUE на full_name)
  const row = rows[0];
  if (!row.employee_number || row.employee_number === null) {
    step2.status = 'not_done';
    step2.message = 'Сведений о заявителе недостаточно для идентификации, нужно сделать запрос';
  } else {
    step2.status = 'ok';
    step2.message = 'Заявитель идентифицирован';
    employee_number = row.employee_number;
    phase2_ok = true;
  }
}

return [{ json: {
  phase2_ok: phase2_ok,
  step2: step2,
  employee_number: employee_number,
  fio: d.fio,
  fio_for_sql: d.fio_for_sql,
  birth_date: d.birth_date,
  personal_number: d.personal_number,
  snils: d.snils,
  step1: d.step1
}}];

// ФАЗА 3: Проверка Мероприятия №1.
const items = $input.all();
const rows = items.map(item => item.json).filter(r => r && r.full_name);
const d = $('Фаза 2: классификация').first().json;

let step3 = { step: 3, name: 'Мероприятие №1' };
let phase3_ok = false;

// БД-ошибка (см. Фаза 2)
const dbError = items.length > 0 && items[0].json && items[0].json.error;
if (dbError) {
  step3.status = 'not_found';
  step3.message = 'Ошибка БД: сервис временно недоступен. Повторите запрос позже.';
  return [{ json: { phase3_ok: false, step3, employee_number: d.employee_number, fio: d.fio, fio_for_sql: d.fio_for_sql, birth_date: d.birth_date, personal_number: d.personal_number, snils: d.snils, step1: d.step1, step2: d.step2 } }];
}

if (rows.length === 0) {
  step3.status = 'not_found';
  step3.message = 'Сведения по данному заявителю отсутствуют';
} else {
  const anyDone = rows.some(r => r.is_done === true);
  if (anyDone) {
    step3.status = 'ok';
    step3.message = 'Мероприятие №1 для заявителя выполнено';
    phase3_ok = true;
  } else {
    step3.status = 'not_done';
    step3.message = 'Для данного заявителя мероприятие №1 не выполнено';
  }
}

return [{ json: {
  phase3_ok: phase3_ok,
  step3: step3,
  employee_number: d.employee_number,
  fio: d.fio,
  fio_for_sql: d.fio_for_sql,
  birth_date: d.birth_date,
  personal_number: d.personal_number,
  snils: d.snils,
  step1: d.step1,
  step2: d.step2
}}];

// ФАЗА 4: Проверка Мероприятия №2 (финальная).
const items = $input.all();
const rows = items.map(item => item.json).filter(r => r && r.full_name);
const d = $('Фаза 3: классификация').first().json;

let step4 = { step: 4, name: 'Мероприятие №2' };

// БД-ошибка (см. Фаза 2)
const dbError = items.length > 0 && items[0].json && items[0].json.error;
if (dbError) {
  step4.status = 'not_found';
  step4.message = 'Ошибка БД: сервис временно недоступен. Повторите запрос позже.';
  return [{ json: { step4, employee_number: d.employee_number, fio: d.fio, birth_date: d.birth_date, personal_number: d.personal_number, snils: d.snils, step1: d.step1, step2: d.step2, step3: d.step3 } }];
}

if (rows.length === 0) {
  step4.status = 'not_found';
  step4.message = 'Сведения по данному заявителю отсутствуют';
} else {
  const anyDone = rows.some(r => r.is_done === true);
  if (anyDone) {
    step4.status = 'ok';
    step4.message = 'Для данного заявителя все мероприятия пройдены успешно';
  } else {
    step4.status = 'not_done';
    step4.message = 'Данному заявителю необходимо обратиться за помощью';
  }
}

return [{ json: {
  step4: step4,
  employee_number: d.employee_number,
  fio: d.fio,
  birth_date: d.birth_date,
  personal_number: d.personal_number,
  snils: d.snils,
  step1: d.step1,
  step2: d.step2,
  step3: d.step3
}}];

// === SSO Phase 3: token presence check ===
// Token может быть в body (JSON request) ИЛИ form-data (file upload).
// Для form-data n8n кладёт поля в корень $json (не в .body).
const item = $input.first();
const j = item && item.json ? item.json : {};
const body = j.body || j;
const token = String((body && body.token) || j.token || '').trim();
if (!token) {
  return [{ json: { __auth_required: true } }];
}
// Прокидываем все исходные поля + binary data дальше (binary не теряется
// автоматически при возврате json — n8n сохраняет binary поле item.binary
// если мы возвращаем СОДЕРЖИМОЕ $json, но не если возвращаем новый объект.
// Используем item.binary в выходе явно.
return [{ json: { ...j, token: token, __auth_ok: true }, binary: item.binary || {} }];

